  1	import { Map as ImmutableMap } from 'immutable';
  2	import * as React from 'react';
  3	import { Trans, useTranslation } from 'react-i18next';
  4	import { useDispatch, useSelector } from 'react-redux';
  5	import { Alert, CodeBlock, CodeBlockAction, CodeBlockCode, Icon } from '@patternfly/react-core';
  6	import { InfoCircleIcon } from '@patternfly/react-icons';
  7	
  8	import { openToolClear } from '../redux-actions';
  9	import { State } from '../redux-reducers';
 10	import CopyAction from './CopyAction';
 11	import Modal from './Modal';
 12	
 13	const ToolModal: React.FC = () => {
 14	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
 15	
 16	  const dispatch = useDispatch();
 17	
 18	  const tool: ImmutableMap<string, unknown> = useSelector((s: State) => {
 19	    const openTool = s.plugins?.ols?.get('openTool');
 20	    return s.plugins?.ols?.getIn([
 21	      'chatHistory',
 22	      openTool.get('chatEntryIndex'),
 23	      'tools',
 24	      openTool.get('id'),
 25	    ]);
 26	  });
 27	
 28	  const onClose = React.useCallback(() => {
 29	    dispatch(openToolClear());
 30	  }, [dispatch]);
 31	
 32	  if (!tool) {
 33	    return null;
 34	  }
 35	  const { args, content, name, status } = tool.toJS();
 36	
 37	  const argsFormatted = Object.entries(args)
 38	    .map(([key, value]) => `${key}=${value}`)
 39	    .join(', ');
 40	
 41	  return (
 42	    <Modal
 43	      className="ols-plugin__attachment-modal"
 44	      isOpen={true}
 45	      onClose={onClose}
 46	      title={
 47	        <>
 48	          <Icon status={status === 'error' ? 'danger' : 'info'}>
 49	            <InfoCircleIcon />
 50	          </Icon>{' '}
 51	          {t('Tool output')}
 52	        </>
 53	      }
 54	    >
 55	      {status === 'error' && (
 56	        <Alert
 57	          className="ols-plugin__alert"
 58	          isInline
 59	          title={t('An unexpected error occurred')}
 60	          variant="danger"
 61	        >
 62	          {t('Please retry or contact support if the issue persists.')}
 63	        </Alert>
 64	      )}
 65	      <p>
 66	        {argsFormatted ? (
 67	          <Trans>
 68	            The following output was generated when running{' '}
 69	            <span className="ols-plugin__code-inline">{{ name }}</span> with arguments{' '}
 70	            <span className="ols-plugin__code-inline">{{ argsFormatted }}</span>.
 71	          </Trans>
 72	        ) : (
 73	          <Trans>
 74	            The following output was generated when running{' '}
 75	            <span className="ols-plugin__code-inline">{{ name }}</span> with no arguments.
 76	          </Trans>
 77	        )}
 78	      </p>
 79	      {content ? (
 80	        <CodeBlock
 81	          actions={
 82	            <>
 83	              <CodeBlockAction />
 84	              <CodeBlockAction>
 85	                <CopyAction value={content} />
 86	              </CodeBlockAction>
 87	            </>
 88	          }
 89	          className="ols-plugin__code-block ols-plugin__code-block--attachment"
 90	        >
 91	          <CodeBlockCode className="ols-plugin__code-block-code">{content}</CodeBlockCode>
 92	        </CodeBlock>
 93	      ) : (
 94	        <Alert
 95	          className="ols-plugin__alert"
 96	          isInline
 97	          title={t('No output returned')}
 98	          variant="info"
 99	        />
100	      )}
101	    </Modal>
102	  );
103	};
104	
105	export default ToolModal;

