 1	import * as React from 'react';
 2	import * as ReactModal from 'react-modal';
 3	import { Title } from '@patternfly/react-core';
 4	
 5	import CloseButton from './CloseButton';
 6	
 7	type Props = {
 8	  children: React.ReactNode;
 9	  className?: string;
10	  isOpen: boolean;
11	  onClose: () => void;
12	  title: React.ReactNode;
13	};
14	
15	const Modal: React.FC<Props> = ({ children, className, isOpen, onClose, title }) => (
16	  <ReactModal
17	    ariaHideApp={false}
18	    className={`modal-dialog ols-plugin__modal${className ? ` ${className}` : ''}`}
19	    isOpen={isOpen}
20	    onRequestClose={onClose}
21	    overlayClassName="co-overlay"
22	  >
23	    <div className="modal-header">
24	      <CloseButton onClose={onClose} />
25	      <Title headingLevel="h2">{title}</Title>
26	    </div>
27	    <div className="modal-body">
28	      <div className="modal-body-content">{children}</div>
29	    </div>
30	  </ReactModal>
31	);
32	
33	export default Modal;

